#!/usr/bin/env bash
set -euo pipefail;source "$(dirname "$0")/lib/android-test.sh";serial=emulator-5554;package=org.archphene.linux.p0392be9c9f103a39d951c2f39c3644d2;while (($#));do case "$1" in --serial)serial="${2:?}";shift 2;;--package)package="${2:?}";shift 2;;*)archphene_die "unknown argument: $1";;esac;done;archphene_test_init "$serial";activity="$(archphene_launcher "$package")";archphene_adb_run logcat -c;archphene_adb_run shell am start -n "$activity" >/dev/null;archphene_wait_log 'mapped=true.*title=KCalc' 30 'ArchpheneInput:V *:S' >/dev/null;ui="$(archphene_capture_ui kcalc-menu-ui)";if [[ "$ui" == *'text="File"'* ]];then archphene_tap_text "$ui" File;else archphene_adb_run shell input tap 40 120;fi;archphene_wait_log 'popup registry=' 10 'ArchpheneInput:V *:S' >/dev/null;if [[ "$ui" == *'text="Settings"'* ]];then archphene_tap_text "$ui" Settings;else archphene_adb_run shell input tap 500 120;fi;sleep 2;log="$(archphene_adb_run logcat -d -s ArchpheneInput:V '*:S')";(( $(grep -c 'popup registry='<<<"$log") >= 2 )) || archphene_die 'menu switching did not produce two popup frames';! archphene_regex_contains "$log" 'protocol error|InvalidGrab|UnconfiguredBuffer' || archphene_die 'Wayland popup error';archphene_note 'KCalc shared-compositor menu switching passed: File -> Settings.'
